public class LoginServlet extends HttpServlet {

 @Override
 protected void doPost(HttpServletRequest request, HttpServletResponse response) 
 throws ServletException, IOException {

 // Step 1: Set character encoding FIRST
 request.setCharacterEncoding("UTF-8");

 // Step 2: Read form parameters
 String username = request.getParameter("username");
 String password = request.getParameter("password");

 // Step 3: Validate input
 if (username == null || username.trim().isEmpty() || 
 password == null || password.trim().isEmpty()) {
 // Set error as request attribute
 request.setAttribute("error", "Username and password are required");
 // Forward back to login form
 RequestDispatcher rd = request.getRequestDispatcher("/login.jsp");
 rd.forward(request, response);
 return;
 }

 // Step 4: Authenticate (mock example)
 if ("admin".equals(username) && "password123".equals(password)) {
 // Create session and store user info
 HttpSession session = request.getSession();
 session.setAttribute("user", username);

 // Redirect to success page (PRG pattern)
 response.sendRedirect(request.getContextPath() + "/dashboard");
 } else {
 // Set error and forward
 request.setAttribute("error", "Invalid credentials");
 RequestDispatcher rd = request.getRequestDispatcher("/login.jsp");
 rd.forward(request, response);
 }
 }
}

public class ApiServlet extends HttpServlet {

 @Override
 protected void doGet(HttpServletRequest request, HttpServletResponse response) 
 throws ServletException, IOException {

 // Prepare data as a Map or create JSON manually
 Map<String, Object> data = new HashMap<>();
 data.put("status", "success");
 data.put("message", "Data retrieved successfully");
 data.put("timestamp", System.currentTimeMillis());

 // Set response content type to JSON
 response.setContentType("application/json");
 response.setCharacterEncoding("UTF-8");

 // Set CORS headers if needed
 response.setHeader("Access-Control-Allow-Origin", "*");

 // Write JSON response
 PrintWriter out = response.getWriter();
 out.print("{\"status\":\"success\",\"message\":\"Data retrieved\"}");
 out.flush();
 }
}

public class SurveyServlet extends HttpServlet {

 @Override
 protected void doPost(HttpServletRequest request, HttpServletResponse response) 
 throws ServletException, IOException {

 request.setCharacterEncoding("UTF-8");

 // Get single parameter
 String userName = request.getParameter("username");

 // Get multiple values (e.g., from checkboxes with same name)
 String[] hobbies = request.getParameterValues("hobbies");

 // Get all parameter names
 Enumeration<String> paramNames = request.getParameterNames();

 // Get complete parameter map
 Map<String, String[]> paramMap = request.getParameterMap();

 // Process the hobbies array
 StringBuilder hobbiesOutput = new StringBuilder();
 if (hobbies != null && hobbies.length > 0) {
 for (int i = 0; i < hobbies.length; i++) {
 hobbiesOutput.append(hobbies[i]);
 if (i < hobbies.length - 1) {
 hobbiesOutput.append(", ");
 }
 }
 } else {
 hobbiesOutput.append("No hobbies selected");
 }

 // Set response type and write output
 response.setContentType("text/html;charset=UTF-8");
 PrintWriter out = response.getWriter();
 out.println("<h1>Thank you, " + userName + "</h1>");
 out.println("<p>Your hobbies: " + hobbiesOutput.toString() + "</p>");
 }
}
